mapper.select:
		SELECT count(*)

		FROM xeus.crms_image image
        LEFT JOIN xeus.mt_usr_desc usr ON image.reg_id = usr.user_id




				AND image.mgr_seq = #{mgrSeq}::numeric



				AND image.reg_id LIKE '%'||#{regId}||'%'



                AND usr.user_nm LIKE '%'||#{regUsrNm}||'%'



				AND image.reg_dat = #{regDat}



				AND image.img_desc = #{imgDesc}



				AND image.img_nm Like '%'||#{imgNm}||'%'



				AND image.img_path = #{imgPath}



                AND image.reg_dat  >=  #{startDat}



                AND image.reg_dat  <=  #{endDat}

        SELECT image.mgr_seq, image.reg_id, usr.user_nm, image.reg_dat, image.img_desc, image.img_nm, image.img_path

		FROM xeus.crms_image image
        LEFT JOIN xeus.mt_usr_desc usr ON image.reg_id = usr.user_id



				AND image.mgr_seq = #{mgrSeq}::numeric



				AND image.reg_id LIKE '%'||#{regId}||'%'



                AND usr.user_nm LIKE '%'||#{regUsrNm}||'%'



				AND image.reg_dat = #{regDat}



				AND image.img_desc = #{imgDesc}



				AND image.img_nm Like '%'||#{imgNm}||'%'



				AND image.img_path = #{imgPath}



                AND image.reg_dat  >=  #{startDat}



                AND image.reg_dat  <=  #{endDat}





                ${sortCol} ${sortTyp}


                image.mgr_seq ASC




            LIMIT ${limit} OFFSET ${offset}

