mapper.select:
INSERT INTO xeus.crms_image(
	reg_id, reg_dat, img_desc, img_nm, img_path
) VALUES (
	#{regId}, #{regDat}, #{imgDesc}, #{imgNm}, #{imgPath}
) RETURNING *;

